@startuml
' Define package structure
package "flutter" as flutter {
  package "src" as src {
    package "painting" as painting {
      class "TextStyle" as TextStyle {
        + TextStyle()
      }
    }
    package "widgets" as widgets {
      class "StatefulWidget" as StatefulWidget {
        + StatefulWidget()
      }
      class "State" as State {
        + State()
      }
      class "GlobalKey<JigsawWidgetState>" as GlobalKey {
        + GlobalKey()
      }
    }
  }
}

package "vivaoinseto_tg" as vivaoinseto_tg {
  package "pages" as pages {
    package "galeria.dart" as galeria {
      class "Galeria" as Galeria {
        + State<Galeria> createState()
      }
      class "_GaleriaState" as _GaleriaState {
        + Widget build()
      }
    }
    package "jogodamemoria.dart" as jogodamemoria {
      class "JogoDaMemoria" as JogoDaMemoria {
        + State<JogoDaMemoria> createState()
      }
      class "_JogoDaMemoriaState" as _JogoDaMemoriaState {
        + TextStyle whiteText
        + bool hideTest
        + Game _game
        + int tries
        + int score
        + void initState()
        + Widget build()
      }
    }
    package "login.dart" as login {
      class "Login" as Login {
        + State<Login> createState()
      }
      class "_LoginState" as _LoginState {
        + Widget build()
      }
    }
    package "quebracabecas.dart" as quebracabecas {
      class "QuebraCabecas" as QuebraCabecas {
        + State<QuebraCabecas> createState()
      }
      class "_QuebraCabecasState" as _QuebraCabecasState {
        + GlobalKey<JigsawWidgetState> puzzleKey
        + Widget build()
      }
    }
  }
  package "cards.dart" as cards {
    class "Game" as Game {
      + Color hiddenCard
      + List<Color>? gameColors
      + List<String>? gameImg
      + List<Color> cards
      + String hiddenCardpath
      + List<String> cards_list
      + int cardCount
      + List<Map<int, String>> matchCheck
      + void initGame()
    }
  }
}

package "dart" as dart {
  package "ui" as ui {
    class "Color" as Color {
      + Color()
    }
  }
}

' Relationships
Galeria --> _GaleriaState
JogoDaMemoria --> _JogoDaMemoriaState
Login --> _LoginState
QuebraCabecas --> _QuebraCabecasState
Game --> Color

' Cross-package relationships
Galeria --> TextStyle
JogoDaMemoria --> State
Login --> State
QuebraCabecas --> GlobalKey
Game --> State

@enduml
